import { WorkflowParameterValueType } from "../types/workflowTypes";

// Keys the Login block auto-generates when a user picks a credential directly
// (`credentials`, `credentials_1`, …). Used as the provenance signal that tells
// auto-generated wrappers apart from user-authored credential variables. The
// Parameters panel rejects new keys matching this pattern so the signal stays sound.
export const AUTO_GENERATED_CREDENTIAL_KEY_PATTERN = /^credentials(_\d+)?$/;

export type BitwardenLoginCredential = {
  key: string;
  description?: string | null;
  parameterType: "credential";
  collectionId: string | null;
  itemId: string | null;
  urlParameterKey: string | null;
};

export type SkyvernCredential = {
  key: string;
  description?: string | null;
  parameterType: "credential";
  credentialId: string;
};

export type OnePasswordCredential = {
  key: string;
  description?: string | null;
  parameterType: "onepassword";
  vaultId: string;
  itemId: string;
};

export type AzureVaultCredential = {
  key: string;
  description?: string | null;
  parameterType: "credential";
  vaultName: string;
  usernameKey: string;
  passwordKey: string;
  totpSecretKey: string | null;
};

export function parameterIsBitwardenCredential(
  parameter: CredentialParameterState,
): parameter is BitwardenLoginCredential {
  return "collectionId" in parameter;
}

export function parameterIsSkyvernCredential(
  parameter: CredentialParameterState,
): parameter is SkyvernCredential {
  return "credentialId" in parameter;
}

export function parameterIsOnePasswordCredential(
  parameter: CredentialParameterState,
): parameter is OnePasswordCredential {
  return "vaultId" in parameter && "itemId" in parameter;
}

export function parameterIsAzureVaultCredential(
  parameter: CredentialParameterState,
): parameter is AzureVaultCredential {
  return (
    "vaultName" in parameter &&
    "usernameKey" in parameter &&
    "passwordKey" in parameter
  );
}

export type CredentialParameterState =
  | BitwardenLoginCredential
  | SkyvernCredential
  | OnePasswordCredential
  | AzureVaultCredential;

export function isAutoGeneratedCredentialKey(key: string): boolean {
  return AUTO_GENERATED_CREDENTIAL_KEY_PATTERN.test(key);
}

// credentialIds wrapped by a user-authored (non-auto-gen) Skyvern credential param.
// Their raw credential row is redundant with the variable's own entry, so the
// Login selector drops it from the direct-credential options.
export function computeWrappedCredentialIds(
  credentialParameters: Array<CredentialParameterState>,
): Set<string> {
  return new Set(
    credentialParameters
      .filter(parameterIsSkyvernCredential)
      .filter((p) => !isAutoGeneratedCredentialKey(p.key))
      .map((p) => p.credentialId),
  );
}

export type ParametersState = Array<
  | {
      key: string;
      parameterType: "workflow";
      dataType: WorkflowParameterValueType;
      description?: string | null;
      defaultValue: unknown;
    }
  | {
      key: string;
      parameterType: "context";
      sourceParameterKey: string;
      description?: string | null;
    }
  | {
      key: string;
      parameterType: "secret";
      identityKey: string;
      identityFields: Array<string>;
      collectionId: string;
      description?: string | null;
      maybe?: boolean;
    }
  | {
      key: string;
      parameterType: "creditCardData";
      itemId: string;
      collectionId: string;
      description?: string | null;
    }
  | CredentialParameterState
>;
